import './index.css';

import {
  Link
} from 'react-router-dom';

import NotesList
from '../../components/common/NotesList';

function StudentDashboard() {

  const userString =
    localStorage.getItem('user');

  let user = {};

  try {

    user = userString
      ? JSON.parse(userString)
      : {};

  } catch (error) {

    console.log(error);

  }

  return (

    <div className="student-dashboard">

      {/* HEADER */}

      <div className="dashboard-header">

        <h1>
          Student Dashboard
        </h1>

        <button
          className="logout-btn"
          onClick={() => {

            localStorage.clear();

            window.location.href = '/';

          }}
        >

          Logout

        </button>

      </div>


      {/* STUDENT CARD */}

      <div className="student-card">

        <h2>
          Welcome
          {' '}
          {user.name || 'Student'}
        </h2>

        <p>

          <strong>
            Student ID:
          </strong>

          {' '}

          {user.id}

        </p>

        <p>

          <strong>
            Email:
          </strong>

          {' '}

          {user.email}

        </p>

        <p>

          <strong>
            Role:
          </strong>

          {' '}

          {user.role}

        </p>

      </div>


      {/* BUTTONS */}

      <div className="student-links">

        <Link
          to="/student-subjects"
          className="student-btn"
        >

          View Subjects

        </Link>

        <Link
          to="/student-marks"
          className="student-btn"
        >

          View Marks

        </Link>

      </div>


      {/* NOTES */}

      <NotesList />

    </div>

  );

}

export default StudentDashboard;
